# --- Utility Functions ---

def hash_token(token):
    """Hash tokens before storage to prevent leakage from storage compromise."""
    return hashlib.sha256(token.encode()).hexdigest()


def generate_secure_token(nbytes=32):
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(nbytes)


def constant_time_compare(a, b):
    """Compare two strings in constant time to prevent timing attacks."""
    return secrets.compare_digest(a, b)


def validate_redirect_uri(client_id, redirect_uri):
    """Validate that the redirect URI is registered for the client."""
    if client_id not in registered_clients:
        return False
    allowed_uris = registered_clients[client_id]["redirect_uris"]
    # Exact match required - no partial matching or wildcards
    return redirect_uri in allowed_uris


def validate_redirect_uri_format(uri):
    """Validate redirect URI format - must be HTTPS."""
    parsed = urlparse(uri)
    if parsed.scheme != "https":
        return False
    if parsed.fragment:
        return False
    return True


def authenticate_client(client_id, client_secret):
    """Authenticate a client using client_id and client_secret."""
    if client_id not in registered_clients:
        return False
    expected_hash = registered_clients[client_id]["client_secret_hash"]
    provided_hash = hashlib.sha256(client_secret.encode()).hexdigest()
    return constant_time_compare(expected_hash, provided_hash)


def cleanup_expired_codes():
    """Remove expired authorization codes."""
    now = time.time()
    expired = [
        code_hash for code_hash, data in auth_codes.items()
        if now - data["created_at"] > AUTH_CODE_EXPIRY_SECONDS
    ]
    for code_hash in expired:
        del auth_codes[code_hash]


def cleanup_expired_tokens():
    """Remove expired access tokens."""
    now = time.time()
    expired = [
        token_hash for token_hash, data in access_tokens.items()
        if now > data["expires_at"]
    ]
    for token_hash in expired:
        del access_tokens[token_hash]


def require_login(f):
    """Decorator to require user login."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if "user_id" not in session:
            return redirect(url_for("login", next=request.url))
        return f(*args, **kwargs)
    return decorated


