@app.route("/login", methods=["GET", "POST"])
def login():
    """User login endpoint."""
    if request.method == "GET":
        return '''
        <form method="post">
            <label>Username: <input name="username" type="text"></label><br>
            <label>Password: <input name="password" type="password"></label><br>
            <button type="submit">Login</button>
        </form>
        '''

    username = request.form.get("username", "")
    password = request.form.get("password", "")

    if username not in users:
        return jsonify({"error": "invalid_credentials"}), 401

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if not constant_time_compare(users[username]["password_hash"], password_hash):
        return jsonify({"error": "invalid_credentials"}), 401

    session["user_id"] = username
    session.regenerate = True  # Regenerate session on login

    next_url = request.args.get("next")
    if next_url:
        # Validate next_url to prevent open redirect
        parsed = urlparse(next_url)
        if parsed.netloc and parsed.netloc != request.host:
            return redirect(url_for("login"))
        return redirect(next_url)

    return jsonify({"message": "Logged in successfully"})


@app.route("/authorize", methods=["GET", "POST"])
@require_login
def authorize():
    """
    Authorization endpoint - generates authorization codes.
    Implements OAuth 2.0 Authorization Code Grant (RFC 6749 Section 4.1).
    """
    client_id = request.args.get("client_id")
    redirect_uri = request.args.get("redirect_uri")
    response_type = request.args.get("response_type")
    scope = request.args.get("scope", "read")
    state = request.args.get("state")

    # Validate required parameters
    if not client_id or not redirect_uri or not response_type:
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    # Validate response_type
    if response_type != "code":
        return jsonify({"error": "unsupported_response_type"}), 400

    # Validate client
    if client_id not in registered_clients:
        return jsonify({"error": "invalid_client", "error_description": "Unknown client"}), 400

    # Validate redirect URI format
    if not validate_redirect_uri_format(redirect_uri):
        return jsonify({"error": "invalid_request", "error_description": "Redirect URI must use HTTPS"}), 400

    # Validate redirect URI is registered for this client
    if not validate_redirect_uri(client_id, redirect_uri):
        # Per RFC 6749 Section 3.1.2.4, do NOT redirect if redirect_uri is invalid
        return jsonify({
            "error": "invalid_request",
            "error_description": "Redirect URI not registered for this client"
        }), 400

    # State parameter is required to prevent CSRF
    if not state:
        return jsonify({"error": "invalid_request", "error_description": "State parameter is required"}), 400

    if request.method == "GET":
        # Show consent screen
        return f'''
        <h2>Authorize {registered_clients[client_id]["name"]}?</h2>
        <p>This application wants to access your account with scope: {scope}</p>
        <form method="post" action="{request.url}">
            <input type="hidden" name="csrf_token" value="{session.get('csrf_token', secrets.token_hex(16))}">
            <button name="approve" value="yes" type="submit">Approve</button>
            <button name="approve" value="no" type="submit">Deny</button>
        </form>
        '''

    # POST - user has made a decision
    approved = request.form.get("approve") == "yes"

    if not approved:
        params = urlencode({"error": "access_denied", "state": state})
        return redirect(f"{redirect_uri}?{params}")

    # Clean up expired codes periodically
    cleanup_expired_codes()

    # Generate authorization code
    code = generate_secure_token(32)
    code_hash = hash_token(code)

    # Store the authorization code with metadata
    auth_codes[code_hash] = {
        "user_id": session["user_id"],
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "scope": scope,
        "created_at": time.time(),
        "used": False  # Track if code has been used
    }

    # Redirect back to client with authorization code
    params = urlencode({"code": code, "state": state})
    return redirect(f"{redirect_uri}?{params}")


@app.route("/token", methods=["POST"])
def token():
    """
    Token endpoint - exchanges authorization codes for access tokens.
    Implements OAuth 2.0 Token Exchange (RFC 6749 Section 4.1.3).
    
    Security: Authorization codes are single-use. If a code is presented
    a second time, all tokens issued for that code are revoked (per RFC 6749
    Section 10.5) to mitigate authorization code replay attacks.
    """
    grant_type = request.form.get("grant_type")
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")

    # Authenticate client
    if not client_id or not client_secret:
        return jsonify({"error": "invalid_client", "error_description": "Client credentials required"}), 401

    if not authenticate_client(client_id, client_secret):
        return jsonify({"error": "invalid_client", "error_description": "Invalid client credentials"}), 401

    if grant_type == "authorization_code":
        return _handle_authorization_code_grant(client_id)
    elif grant_type == "refresh_token":
        return _handle_refresh_token_grant(client_id)
    else:
        return jsonify({"error": "unsupported_grant_type"}), 400


def _handle_authorization_code_grant(client_id):
    """Handle the authorization code grant type."""
    code = request.form.get("code")
    redirect_uri = request.form.get("redirect_uri")

    if not code or not redirect_uri:
        return jsonify({"error": "invalid_request", "error_description": "Missing code or redirect_uri"}), 400

    code_hash = hash_token(code)

    # Look up the authorization code
    if code_hash not in auth_codes:
        return jsonify({"error": "invalid_grant", "error_description": "Invalid authorization code"}), 400

    code_data = auth_codes[code_hash]

    # Check if code has expired
    if time.time() - code_data["created_at"] > AUTH_CODE_EXPIRY_SECONDS:
        del auth_codes[code_hash]
        return jsonify({"error": "invalid_grant", "error_description": "Authorization code has expired"}), 400

    # Check if code has already been used (RFC 6749 Section 10.5)
    # If a code is used more than once, revoke all tokens issued with it
    if code_data["used"]:
        # Revoke all tokens associated with this authorization code
        _revoke_tokens_for_code(code_hash)
        del auth_codes[code_hash]
        return jsonify({
            "error": "invalid_grant",
            "error_description": "Authorization code has already been used. All associated tokens have been revoked."
        }), 400

    # Validate that the code was issued to this client
    if code_data["client_id"] != client_id:
        return jsonify({"error": "invalid_grant", "error_description": "Code was not issued to this client"}), 400

    # Validate redirect_uri matches the one used in the authorization request
    if code_data["redirect_uri"] != redirect_uri:
        return jsonify({"error": "invalid_grant", "error_description": "Redirect URI mismatch"}), 400

    # Mark code as used (single-use enforcement)
    auth_codes[code_hash]["used"] = True

    # Generate access token and refresh token
    access_token = generate_secure_token(32)
    refresh_token_value = generate_secure_token(32)

    access_token_hash = hash_token(access_token)
    refresh_token_hash = hash_token(refresh_token_value)

    now = time.time()

    access_tokens[access_token_hash] = {
        "user_id": code_data["user_id"],
        "client_id": client_id,
        "scope": code_data["scope"],
        "created_at": now,
        "expires_at": now + ACCESS_TOKEN_EXPIRY_SECONDS,
        "auth_code_hash": code_hash  # Track which auth code issued this token
    }

    refresh_tokens[refresh_token_hash] = {
        "user_id": code_data["user_id"],
        "client_id": client_id,
        "scope": code_data["scope"],
        "created_at": now,
        "expires_at": now + REFRESH_TOKEN_EXPIRY_SECONDS,
        "auth_code_hash": code_hash  # Track which auth code issued this token
    }

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": ACCESS_TOKEN_EXPIRY_SECONDS,
        "refresh_token": refresh_token_value,
        "scope": code_data["scope"]
    })


def _handle_refresh_token_grant(client_id):
    """Handle the refresh token grant type."""
    refresh_token_value = request.form.get("refresh_token")

    if not refresh_token_value:
        return jsonify({"error": "invalid_request", "error_description": "Missing refresh_token"}), 400

    refresh_token_hash = hash_token(refresh_token_value)

    if refresh_token_hash not in refresh_tokens:
        return jsonify({"error": "invalid_grant", "error_description": "Invalid refresh token"}), 400

    rt_data = refresh_tokens[refresh_token_hash]

    # Check expiry
    if time.time() > rt_data["expires_at"]:
        del refresh_tokens[refresh_token_hash]
        return jsonify({"error": "invalid_grant", "error_description": "Refresh token has expired"}), 400

    # Validate client
    if rt_data["client_id"] != client_id:
        return jsonify({"error": "invalid_grant", "error_description": "Token was not issued to this client"}), 400

    # Rotate refresh token (invalidate old one, issue new one)
    del refresh_tokens[refresh_token_hash]

    # Generate new tokens
    new_access_token = generate_secure_token(32)
    new_refresh_token = generate_secure_token(32)

    new_access_token_hash = hash_token(new_access_token)
    new_refresh_token_hash = hash_token(new_refresh_token)

    now = time.time()

    access_tokens[new_access_token_hash] = {
        "user_id": rt_data["user_id"],
        "client_id": client_id,
        "scope": rt_data["scope"],
        "created_at": now,
        "expires_at": now + ACCESS_TOKEN_EXPIRY_SECONDS,
        "auth_code_hash": rt_data.get("auth_code_hash")
    }

    refresh_tokens[new_refresh_token_hash] = {
        "user_id": rt_data["user_id"],
        "client_id": client_id,
        "scope": rt_data["scope"],
        "created_at": now,
        "expires_at": now + REFRESH_TOKEN_EXPIRY_SECONDS,
        "auth_code_hash": rt_data.get("auth_code_hash")
    }

    return jsonify({
        "access_token": new_access_token,
        "token_type": "Bearer",
        "expires_in": ACCESS_TOKEN_EXPIRY_SECONDS,
        "refresh_token": new_refresh_token,
        "scope": rt_data["scope"]
    })


def _revoke_tokens_for_code(code_hash):
    """Revoke all access and refresh tokens issued for a given authorization code."""
    # Revoke access tokens
    to_revoke = [
        th for th, data in access_tokens.items()
        if data.get("auth_code_hash") == code_hash
    ]
    for th in to_revoke:
        del access_tokens[th]

    # Revoke refresh tokens
    to_revoke = [
        th for th, data in refresh_tokens.items()
        if data.get("auth_code_hash") == code_hash
    ]
    for th in to_revoke:
        del refresh_tokens[th]


@app.route("/revoke", methods=["POST"])
def revoke():
    """Token revocation endpoint (RFC 7009)."""
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")

    if not client_id or not client_secret:
        return jsonify({"error": "invalid_client"}), 401

    if not authenticate_client(client_id, client_secret):
        return jsonify({"error": "invalid_client"}), 401

    token_value = request.form.get("token")
    token_type_hint = request.form.get("token_type_hint", "access_token")

    if not token_value:
        return jsonify({"error": "invalid_request"}), 400

    token_hash_value = hash_token(token_value)

    if token_type_hint == "refresh_token":
        if token_hash_value in refresh_tokens:
            if refresh_tokens[token_hash_value]["client_id"] == client_id:
                del refresh_tokens[token_hash_value]
    else:
        if token_hash_value in access_tokens:
            if access_tokens[token_hash_value]["client_id"] == client_id:
                del access_tokens[token_hash_value]

    # Always return 200 per RFC 7009
    return jsonify({}), 200


@app.route("/introspect", methods=["POST"])
def introspect():
    """Token introspection endpoint (RFC 7662)."""
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")

    if not client_id or not client_secret:
        return jsonify({"error": "invalid_client"}), 401

    if not authenticate_client(client_id, client_secret):
        return jsonify({"error": "invalid_client"}), 401

    token_value = request.form.get("token")
    if not token_value:
        return jsonify({"active": False})

    token_hash_value = hash_token(token_value)

    # Clean up expired tokens
    cleanup_expired_tokens()

    if token_hash_value in access_tokens:
        data = access_tokens[token_hash_value]
        return jsonify({
            "active": True,
            "scope": data["scope"],
            "client_id": data["client_id"],
            "username": data["user_id"],
            "token_type": "Bearer",
            "exp": int(data["expires_at"]),
            "iat": int(data["created_at"])
        })

    return jsonify({"active": False})


