    cleanup_expired_tokens()

    if token_hash_value not in access_tokens:
        return jsonify({"error": "invalid_token", "error_description": "Token is invalid or expired"}), 401

    token_data = access_tokens[token_hash_value]

    if time.time() > token_data["expires_at"]:
        del access_tokens[token_hash_value]
        return jsonify({"error": "invalid_token", "error_description": "Token has expired"}), 401

    return jsonify({
        "user_id": token_data["user_id"],
        "scope": token_data["scope"],
        "message": f"Hello, {token_data['user_id']}! You have access with scope: {token_data['scope']}"
    })


